document.addEventListener("DOMContentLoaded",function(){const shareContainer=document.getElementById("social-share-container");if(shareContainer){const pageUrl=encodeURIComponent(window.location.href);const pageTitle=encodeURIComponent(document.title);const twitterLink=`https://twitter.com/intent/tweet?url=${pageUrl}&text=${pageTitle}`;const linkedinLink=`https://www.linkedin.com/shareArticle?mini=true&url=${pageUrl}&title=${pageTitle}`;const facebookLink=`https://www.facebook.com/sharer/sharer.php?u=${pageUrl}`;shareContainer.innerHTML=`
            <h3>Share this Post:</h3>
            <div class="social-buttons">
                <a href="${twitterLink}" target="_blank" rel="noopener noreferrer" class="social-button twitter">Twitter</a>
                <a href="${linkedinLink}" target="_blank" rel="noopener noreferrer" class="social-button linkedin">LinkedIn</a>
                <a href="${facebookLink}" target="_blank" rel="noopener noreferrer" class="social-button facebook">Facebook</a>
            </div>
        `}});